import java.util.ArrayList;
import java.util.List;

/**
 * File service class providing functionality to find files by pattern
 */
public class FileService {

    /**
     * Find files matching the specified pattern
     *
     * @param searchDir   Path of the directory to search
     * @param filePattern Filename pattern (supports wildcards)
     * @return List of found files, one per line; returns error message on failure
     */
    public String findFilesWithPattern(String searchDir, String filePattern) {
        if (searchDir == null || filePattern == null || searchDir.trim().isEmpty()) {
            return "Error: Search directory or file pattern is empty.";
        }

        // Validate inputs to prevent path traversal and command injection
        if (!isValidPath(searchDir) || !isValidPattern(filePattern)) {
            return "Error: Invalid search directory or file pattern.";
        }

        // Use ProcessBuilder instead of Runtime.exec with string command
        // This avoids shell interpretation and command injection
        List<String> command = new ArrayList<>();
        command.add("find");
        command.add(searchDir);
        command.add("-type");
        command.add("f");
        command.add("-name");
        command.add(filePattern);

        ProcessBuilder processBuilder = new ProcessBuilder(command);
        processBuilder.redirectErrorStream(true); // Merge stderr with stdout

        Process process = null;
        try {
            // 2. Execute command
            process = processBuilder.start();

            // 3. Wait for command execution to complete
            int exitCode = process.waitFor();

            // 4. Read output
            String output = readStream(process.getInputStream());

            // 5. Limit results to 10 files (done in Java instead of shell)
            String limitedOutput = limitResults(output, 10);

            // 6. Determine result based on exit code and output
            if (exitCode != 0) {
                // Command execution failed, return error information
                return "Error: File search failed.\n" + output;
            }

            if (limitedOutput.isEmpty()) {
                return "No matching files found.";
            }

            return limitedOutput.trim();
        } catch (IOException | InterruptedException e) {
            if (e instanceof InterruptedException) {
                Thread.currentThread().interrupt(); // Re-set interrupt status
            }
            return "Error: Exception occurred while executing command: " + e.getMessage();
        } finally {
            if (process != null) {
                // Ensure child process is destroyed
                process.destroy();
            }
        }
    }

    /**
     * Validates that the path is safe and doesn't contain injection attempts
     * 
     * @param path The path to validate
     * @return true if the path is safe, false otherwise
     */
    private boolean isValidPath(String path) {
        // Check for common command injection characters
        String[] dangerousChars = {";", "&", "|", "$", "`", ">", "<", "!", "\n", "\r"};
        for (String dangerousChar : dangerousChars) {
            if (path.contains(dangerousChar)) {
                return false;
            }
        }

        // Check for path traversal attempts
        if (path.contains("..")) {
            return false;
        }

        // Additional validation: ensure path doesn't start with dangerous patterns
        if (path.startsWith("-") || path.startsWith("--")) {
            return false;
        }

        return true;
    }

    /**
     * Validates that the file pattern is safe
     * 
     * @param pattern The pattern to validate
     * @return true if the pattern is safe, false otherwise
     */
    private boolean isValidPattern(String pattern) {
        // Check for common command injection characters
        String[] dangerousChars = {";", "&", "|", "$", "`", ">", "<", "!", "\n", "\r"};
        for (String dangerousChar : dangerousChars) {
            if (pattern.contains(dangerousChar)) {
                return false;
            }
        }

        // Additional validation: ensure pattern doesn't start with dangerous patterns
        if (pattern.startsWith("-") || pattern.startsWith("--")) {
            return false;
        }

        return true;
    }

    /**
     * Limits the number of results to the specified maximum
     * 
     * @param output The full output from find command
     * @param maxResults Maximum number of results to return
     * @return Limited output with at most maxResults lines
     */
    private String limitResults(String output, int maxResults) {
        if (output == null || output.isEmpty()) {
            return "";
        }

        String[] lines = output.split("\n");
        StringBuilder limited = new StringBuilder();

        for (int i = 0; i < Math.min(lines.length, maxResults); i++) {
            limited.append(lines[i]).append("\n");
        }

        return limited.toString();
    }

    /**
     * Helper method to read input stream and return as string
     *
     * @param inputStream Input stream
     * @return String read from the stream
     * @throws IOException On read error
     */
    private String readStream(InputStream inputStream) throws IOException {
        StringBuilder result = new StringBuilder();
        try (BufferedReader reader = new BufferedReader(new InputStreamReader(inputStream))) {
            String line;
            while ((line = reader.readLine()) != null) {
                result.append(line).append("\n");
            }
        }
        return result.toString();
    }
}

